import json,re,os,requests,pandas as pd
from concurrent.futures import ThreadPoolExecutor
rep=json.load(open('work/reports.json'))
os.makedirs('work/faa',exist_ok=True)
os.makedirs('work/fna',exist_ok=True)
def san(n): return re.sub(r'[^A-Za-z0-9.]','_',n)
def ftp_base(acc,name):
    p=acc.split('_')[1].split('.')[0]
    return f"https://ftp.ncbi.nlm.nih.gov/genomes/all/{acc[:3]}/{p[0:3]}/{p[3:6]}/{p[6:9]}/{acc}_{san(name)}"
def work(acc):
    m=rep[acc]; name=m['assembly_name']
    if not name: return (acc,'noname')
    faa=f'work/faa/{acc}.faa.gz'
    if os.path.exists(faa) and os.path.getsize(faa)>100: return (acc,'have')
    base=ftp_base(acc,name); stem=f"{acc}_{san(name)}"
    url=f"{base}/{stem}_protein.faa.gz"
    for att in range(3):
        try:
            r=requests.get(url,timeout=90)
            if r.status_code==200 and len(r.content)>100:
                open(faa,'wb').write(r.content); return (acc,'faa')
            elif r.status_code==404: break
        except Exception: pass
    # fallback: genomic fna
    fna=f'work/fna/{acc}.fna.gz'
    if os.path.exists(fna) and os.path.getsize(fna)>100: return (acc,'have_fna')
    url2=f"{base}/{stem}_genomic.fna.gz"
    for att in range(3):
        try:
            r=requests.get(url2,timeout=120)
            if r.status_code==200 and len(r.content)>100:
                open(fna,'wb').write(r.content); return (acc,'fna')
            elif r.status_code==404: break
        except Exception: pass
    return (acc,'FAIL')
accs=list(rep.keys())
from collections import Counter
c=Counter()
with ThreadPoolExecutor(max_workers=24) as ex:
    for i,(acc,st) in enumerate(ex.map(work,accs)):
        c[st]+=1
        if i%300==0: print(i,dict(c),flush=True)
print('FINAL',dict(c))
fails=[a for a in accs if not (os.path.exists(f'work/faa/{a}.faa.gz') or os.path.exists(f'work/fna/{a}.fna.gz'))]
json.dump(fails,open('work/dl_fails.json','w'))
print('fails',len(fails),fails[:20])
